    "infrastructure": {
      "rating": "red",
      "evidence": [
        "get_network_status shows the 'mongo' container has 'exited'.",
        "get_network_topology shows multiple INACTIVE links to MongoDB from UDR, PCF, BSF, and NSSF."
      ],
      "note": "A critical database has failed, impacting multiple network functions."
    },
    "ran": {
      "rating": "green",
      "evidence": [
        "AMF metrics show 2 UEs are connected.",
        "No RAN-specific metrics are anomalous."
